//! On-disk state, shared with monster-guard / monster-resident under
//! `$MONSTER_GUARD_HOME` (default `~/.moonshine.d`):
//!   root.key       shared root authority secret (written by guard/resident)
//!   revocations.json  the RevocationSet honored by the lease supervisor
//!   fleet.json     the monster-swarm fleet ledger (this crate's writer)
//!   fleet.lock     advisory (flock) lock serializing fleet read-modify-write

use std::fs::File;
use std::os::unix::fs::PermissionsExt;
use std::os::unix::io::AsRawFd;
use std::path::PathBuf;

use a0n_auth::{Keypair, RevocationSet};

use crate::ledger::Fleet;

pub fn home() -> PathBuf {
    if let Ok(h) = std::env::var("MONSTER_GUARD_HOME") {
        return PathBuf::from(h);
    }
    let base = std::env::var("HOME").unwrap_or_else(|_| ".".to_string());
    PathBuf::from(base).join(".moonshine.d")
}

/// Load (or create) the shared root authority. The same root the resident and
/// guard use, so capabilities verified here are rooted at one authority.
pub fn ensure_root() -> Result<Keypair, String> {
    let dir = home();
    std::fs::create_dir_all(&dir).map_err(|e| format!("create {}: {e}", dir.display()))?;
    let key_path = dir.join("root.key");
    if key_path.exists() {
        let hex = std::fs::read_to_string(&key_path).map_err(|e| e.to_string())?;
        Keypair::from_secret_hex(hex.trim()).map_err(|e| e.to_string())
    } else {
        let kp = Keypair::generate();
        std::fs::write(&key_path, kp.secret_hex()).map_err(|e| e.to_string())?;
        let _ = std::fs::set_permissions(&key_path, std::fs::Permissions::from_mode(0o600));
        Ok(kp)
    }
}

/// The fleet root authority's secret-key hex — the signing material for the
/// tamper-evident audit chain ([`crate::audit`]), which signs every lifecycle
/// entry with the root key so a forged entry not signed by the root is
/// detectable. This is the same secret in the 0600 `root.key` file; it is
/// returned here for the in-process signer ONLY and MUST never be logged or
/// surfaced. Loads (or creates) the root via [`ensure_root`].
pub fn root_secret_hex() -> Result<String, String> {
    Ok(ensure_root()?.secret_hex())
}

pub fn load_revocations() -> RevocationSet {
    match std::fs::read_to_string(home().join("revocations.json")) {
        Ok(s) => serde_json::from_str(&s).unwrap_or_default(),
        Err(_) => RevocationSet::default(),
    }
}

pub fn fleet_path() -> PathBuf {
    home().join("fleet.json")
}

pub fn load_fleet() -> Fleet {
    match std::fs::read_to_string(fleet_path()) {
        Ok(s) => serde_json::from_str(&s).unwrap_or_default(),
        Err(_) => Fleet::default(),
    }
}

pub fn save_fleet(fleet: &Fleet) -> Result<(), String> {
    let dir = home();
    std::fs::create_dir_all(&dir).map_err(|e| e.to_string())?;
    let json = serde_json::to_string_pretty(fleet).map_err(|e| e.to_string())?;
    let path = fleet_path();
    // Atomic write: a torn/partial ledger means a leaked or orphaned subagent,
    // so write a per-pid temp and rename (atomic on the same filesystem). The
    // ledger reveals fleet topology (ids, dids, pids), so keep it owner-only.
    let tmp = dir.join(format!(".fleet.json.tmp.{}", std::process::id()));
    std::fs::write(&tmp, &json).map_err(|e| e.to_string())?;
    let _ = std::fs::set_permissions(&tmp, std::fs::Permissions::from_mode(0o600));
    std::fs::rename(&tmp, &path).map_err(|e| {
        let _ = std::fs::remove_file(&tmp);
        e.to_string()
    })?;
    Ok(())
}

// --- fleet read-modify-write lock ------------------------------------------
//
// `save_fleet` is atomic (write-temp + rename), so a reader never sees a torn
// ledger. But a *mutator* does load → mutate → save, and two concurrent
// mutators can both load the same fleet, mutate independently, and have the
// later save clobber the earlier one (a lost update — e.g. two spawns where
// only one subagent ends up in the ledger while both processes hold a lease).
//
// `FleetLock` serializes that critical section with an advisory POSIX file lock
// (`flock(LOCK_EX)`) on `fleet.lock`. Mutators acquire it before `load_fleet`
// and hold it (via the returned guard) until after `save_fleet`. It is advisory
// — only callers that take the lock are serialized — and that is exactly the
// guarantee we need, since this crate is the sole writer of `fleet.json`.

pub fn fleet_lock_path() -> PathBuf {
    home().join("fleet.lock")
}

/// An held exclusive advisory lock over the fleet ledger. Released on drop
/// (explicitly via `flock(LOCK_UN)`, and again by the kernel when the fd
/// closes), so the lock is never leaked even on an early `?` return.
pub struct FleetLock {
    file: File,
}

impl FleetLock {
    /// Acquire the exclusive fleet lock, blocking until it is available.
    /// Idempotent re-entrancy is NOT provided: a single thread must not nest
    /// two `acquire` calls (flock would deadlock against this same fd's lock on
    /// most platforms only across processes; within a process the second
    /// LOCK_EX on a *different* fd would block — so hold exactly one).
    pub fn acquire() -> Result<FleetLock, String> {
        let dir = home();
        std::fs::create_dir_all(&dir).map_err(|e| e.to_string())?;
        let path = fleet_lock_path();
        let file = File::options()
            .create(true)
            .read(true)
            .write(true)
            .open(&path)
            .map_err(|e| format!("open fleet lock {}: {e}", path.display()))?;
        // The lockfile reveals nothing, but keep it owner-only for consistency
        // with the rest of $MONSTER_GUARD_HOME.
        let _ = std::fs::set_permissions(&path, std::fs::Permissions::from_mode(0o600));
        // Retry across EINTR; flock can be interrupted by a signal.
        loop {
            let rc = unsafe { libc::flock(file.as_raw_fd(), libc::LOCK_EX) };
            if rc == 0 {
                break;
            }
            let err = std::io::Error::last_os_error();
            if err.raw_os_error() == Some(libc::EINTR) {
                continue;
            }
            return Err(format!("flock fleet lock: {err}"));
        }
        Ok(FleetLock { file })
    }
}

impl Drop for FleetLock {
    fn drop(&mut self) {
        // Best-effort explicit unlock; the kernel also releases on close.
        unsafe {
            libc::flock(self.file.as_raw_fd(), libc::LOCK_UN);
        }
    }
}

// --- per-agent secret keys (for invocation signatures) ---------------------
//
// Each subagent gets its own DID + secret. The secret is written to a 0600
// keyfile under `agents/` (never stored in the ledger and never passed in the
// environment); only the *path* is handed to the node, which reads it to sign.

pub fn agents_dir() -> PathBuf {
    home().join("agents")
}

pub fn agent_key_path(id: &str) -> PathBuf {
    agents_dir().join(format!("{id}.key"))
}

pub fn write_agent_key(id: &str, secret_hex: &str) -> Result<PathBuf, String> {
    let dir = agents_dir();
    std::fs::create_dir_all(&dir).map_err(|e| e.to_string())?;
    let _ = std::fs::set_permissions(&dir, std::fs::Permissions::from_mode(0o700));
    let path = agent_key_path(id);
    std::fs::write(&path, secret_hex).map_err(|e| e.to_string())?;
    std::fs::set_permissions(&path, std::fs::Permissions::from_mode(0o600))
        .map_err(|e| e.to_string())?;
    Ok(path)
}

pub fn remove_agent_key(id: &str) {
    let _ = std::fs::remove_file(agent_key_path(id));
}

// --- per-agent signed oath-tokens (the Ulysses pact) -----------------------
//
// At spawn, the agent cryptographically swears its oath: it signs the oath
// terms into a UCAN oath-token with its OWN freshly-minted keypair (iss = aud =
// the agent DID — Ulysses ties itself to the mast). The signed token is written
// here, 0600, and its *path* is handed to monster-guard, which verifies the
// signature at admission. Like the keyfile, the token is removed on reap /
// reconcile so the directory tracks the live fleet.

pub fn oath_tokens_dir() -> PathBuf {
    home().join("oath-tokens")
}

pub fn oath_token_path(id: &str) -> PathBuf {
    oath_tokens_dir().join(format!("{id}.oath.ucan"))
}

/// Write a signed oath-token to the agent's 0600 token file and return its path
/// (the path handed to `monster-guard delegate --oath`). The directory is 0700.
pub fn write_oath_token(id: &str, token: &str) -> Result<PathBuf, String> {
    let dir = oath_tokens_dir();
    std::fs::create_dir_all(&dir).map_err(|e| e.to_string())?;
    let _ = std::fs::set_permissions(&dir, std::fs::Permissions::from_mode(0o700));
    let path = oath_token_path(id);
    std::fs::write(&path, token).map_err(|e| e.to_string())?;
    std::fs::set_permissions(&path, std::fs::Permissions::from_mode(0o600))
        .map_err(|e| e.to_string())?;
    Ok(path)
}

pub fn remove_oath_token(id: &str) {
    let _ = std::fs::remove_file(oath_token_path(id));
}

// --- per-agent node logs ----------------------------------------------------

pub fn logs_dir() -> PathBuf {
    home().join("logs")
}

pub fn log_path(name: &str) -> PathBuf {
    logs_dir().join(format!("{name}.log"))
}

/// Ensure the (owner-only) logs dir exists and return the agent's log path.
pub fn ensure_log_path(name: &str) -> Result<PathBuf, String> {
    let dir = logs_dir();
    std::fs::create_dir_all(&dir).map_err(|e| e.to_string())?;
    let _ = std::fs::set_permissions(&dir, std::fs::Permissions::from_mode(0o700));
    Ok(log_path(name))
}

/// Subagent ids index the guard name and the swarm source_id; keep them safe.
pub fn valid_id(id: &str) -> bool {
    !id.is_empty()
        && id.len() <= 64
        && id
            .chars()
            .all(|c| c.is_ascii_alphanumeric() || c == '-' || c == '_')
}

/// A crate-wide guard serializing tests that mutate the process-global
/// `$MONSTER_GUARD_HOME`, so a `home()`-based test never observes another
/// test's home under the runner's parallel threads.
#[cfg(test)]
pub(crate) static ENV_GUARD: std::sync::Mutex<()> = std::sync::Mutex::new(());

#[cfg(test)]
mod tests {
    use super::*;
    use super::ENV_GUARD;

    /// The fleet lock must serialize concurrent read-modify-writes so updates
    /// are not lost. Without the lock, N threads each doing load-bump-save race
    /// and the final count is < N; with it, every increment survives.
    #[test]
    fn fleet_lock_serializes_read_modify_write() {
        let _env = ENV_GUARD.lock().unwrap();
        let dir = std::env::temp_dir().join(format!("monster-swarm-locktest-{}", std::process::id()));
        let _ = std::fs::remove_dir_all(&dir);
        std::fs::create_dir_all(&dir).unwrap();
        // Isolate this test's $MONSTER_GUARD_HOME; no other test touches it.
        std::env::set_var("MONSTER_GUARD_HOME", &dir);

        // Seed a zero-count fleet (vent_burden is our shared counter).
        save_fleet(&Fleet::default()).unwrap();

        const THREADS: u32 = 16;
        let handles: Vec<_> = (0..THREADS)
            .map(|_| {
                let dir = dir.clone();
                std::thread::spawn(move || {
                    // Each thread re-asserts the home (threads share env, but be
                    // explicit) then does a locked read-modify-write.
                    std::env::set_var("MONSTER_GUARD_HOME", &dir);
                    let _lock = FleetLock::acquire().expect("acquire fleet lock");
                    let mut fleet = load_fleet();
                    let before = fleet.vent_burden;
                    // Widen the race window: a non-atomic bump that would lose
                    // updates without the lock.
                    std::thread::yield_now();
                    fleet.vent_burden = before + 1;
                    save_fleet(&fleet).expect("save fleet");
                })
            })
            .collect();
        for h in handles {
            h.join().unwrap();
        }

        let final_count = load_fleet().vent_burden;
        std::env::remove_var("MONSTER_GUARD_HOME");
        let _ = std::fs::remove_dir_all(&dir);
        assert_eq!(
            final_count, THREADS,
            "lost an update under concurrency: {final_count} of {THREADS} survived"
        );
    }

    #[test]
    fn fleet_lock_releases_on_drop() {
        let _env = ENV_GUARD.lock().unwrap();
        let dir = std::env::temp_dir().join(format!("monster-swarm-lockdrop-{}", std::process::id()));
        let _ = std::fs::remove_dir_all(&dir);
        std::fs::create_dir_all(&dir).unwrap();
        std::env::set_var("MONSTER_GUARD_HOME", &dir);

        // Take and drop the lock, then take it again — must not deadlock.
        {
            let _l = FleetLock::acquire().expect("first acquire");
        }
        {
            let _l = FleetLock::acquire().expect("second acquire after drop");
        }

        std::env::remove_var("MONSTER_GUARD_HOME");
        let _ = std::fs::remove_dir_all(&dir);
    }
}
